solutions.javascript:
// Solution
function validatePortMapping(portMapping) {
  if (portMapping.hostPort >= 0 && portMapping.hostPort <= 65535 && portMapping.containerPort >= 0 && portMapping.containerPort <= 32767) {
    return true;
  } else {
    return false;
  }
}

