class Solution:
  def validate_port_mapping(self, port_mapping) -> bool:
    if (port_mapping.hostPort >= 0 and port_mapping.hostPort <= 65535 and port_mapping.containerPort >= 0 and port_mapping.containerPort <= 32767):
      return True
    else:
      return False
